import { useEffect, useState } from "react";
import ListItem from "../../components/People/ListItem";

const Pending = (props) => {
  const [pendingRequests, setPendingRequests] = useState([]);
  console.log(pendingRequests);
  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await fetch("/user/pending", {
          headers: {
            Authorization: "Bearer " + props.token,
          },
        });
        const resData = await res.json();

        setPendingRequests(resData.pendingRequests);
      } catch (err) {
        console.log(err);
      }
    };
    fetchData();
  }, [props.token]);

  const acceptRequest = async () => {
    const res = await fetch("/user/accept-request", {
      method: "POST",
      body: JSON.stringify(),
      headers: {
        "Content-Type": "application/json",
        Authorization: "Bearer " + props.token,
      },
    });
  }


  return (
    <div>
      {/* {pendingRequests.map((req) => {
        if (req.requestType === "outgoing") {
          return (
            <ListItem
              key={req.requestId}
              title={req.username}
              description="Outgoing Friend Request"
            ></ListItem>
          );
        }
        return (
          <ListItem
            key={req.requestId}
            title={req.username}
            description="Incoming Friend Request"
          ></ListItem>
        );
      })} */}
    </div>
  );
};

export default Pending;
